def part1(commands):
    def step(state, cmdval):
        cmd, val = cmdval
        h, d = state
        if cmd == "forward":
            return (h + val, d)
        elif cmd == "down":
            return (h, d + val)
        else:
            return (h, d - val)
    h, d = reduce(step, map(parse, commands), (0, 0))
    return h * d

