        cmd, val = cmdval
        h, d, aim = state
        if cmd == "forward":
            return (h + val, d + aim * val, aim)
        elif cmd == "down":
            return (h, d, aim + val)
        else:
            return (h, d, aim - val)
    h, d, _ = reduce(step, map(parse, commands), (0, 0, 0))
    return h * d

