from sys import stdin
from collections import Counter

def parse(line):
    a, b = line.strip().split(" -> ")
    x1, y1 = map(int, a.split(","))
    x2, y2 = map(int, b.split(","))
    return (x1, y1, x2, y2)

def sign(x):
    return (x > 0) - (x < 0)

def points(x1, y1, x2, y2):
    dx, dy = sign(x2 - x1), sign(y2 - y1)
    n = max(abs(x2 - x1), abs(y2 - y1))
    return ((x1 + i * dx, y1 + i * dy) for i in range(n + 1))

def overlaps(lines, diag):
    pts = (pt for x1, y1, x2, y2 in lines if diag or x1 == x2 or y1 == y2 for pt in points(x1, y1, x2, y2))
    return sum(v > 1 for v in Counter(pts).values())

lines = list(map(parse, filter(str.strip, stdin)))
print(overlaps(lines, False))
print(overlaps(lines, True))

