def part1(numbers):
    n = len(numbers)
    width = len(numbers[0])
    gamma = ""
    epsilon = ""
    for i in range(width):
        ones = sum(num[i] == '1' for num in numbers)
        if ones > n // 2:
            gamma += '1'
            epsilon += '0'
        else:
            gamma += '0'
            epsilon += '1'
    return int(gamma, 2) * int(epsilon, 2)

def filter_numbers(numbers, criteria):
    width = len(numbers[0])
    candidates = numbers[:]
    for i in range(width):
        if len(candidates) == 1:
            break
        ones = sum(num[i] == '1' for num in candidates)
        zeros = len(candidates) - ones
        if criteria == "oxygen":
            keep = '1' if ones >= zeros else '0'
        else:
            keep = '0' if zeros <= ones else '1'
        candidates = [num for num in candidates if num[i] == keep]
    return int(candidates[0], 2)

def part2(numbers):
    oxygen = filter_numbers(numbers, "oxygen")
    co2 = filter_numbers(numbers, "co2")
    return oxygen * co2

